<!DOCTYPE html>
<html lang="es">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Recuperar Contraseña — INTECAP Quiché</title>
    <link href="../ADMIN/img/intecap.png" rel="icon" type="image/png">
    <link rel="preconnect" href="https://fonts.googleapis.com">
    <link rel="preconnect" href="https://fonts.gstatic.com" crossorigin>
    <link href="https://fonts.googleapis.com/css2?family=Nunito:wght@400;600;700;800&family=Poppins:wght@300;400;600;700&display=swap" rel="stylesheet">
    <link rel="stylesheet" href="https://cdnjs.cloudflare.com/ajax/libs/font-awesome/6.4.0/css/all.min.css">
    <style>
        *, *::before, *::after { margin:0; padding:0; box-sizing:border-box; }

        :root {
            --blue-dark:  #0a3d8f;
            --blue-mid:   #1565c0;
            --blue-main:  #1e88e5;
            --blue-light: #42a5f5;
            --shadow:     0 20px 60px rgba(10,61,143,.35);
        }

        body {
            min-height: 100vh;
            display: flex;
            align-items: center;
            justify-content: center;
            background: linear-gradient(135deg,var(--blue-dark) 0%,var(--blue-mid) 40%,var(--blue-main) 70%,var(--blue-light) 100%);
            font-family: 'Poppins', sans-serif;
            overflow: hidden;
            position: relative;
        }

        .bg-blob { position:fixed; border-radius:50%; filter:blur(70px); opacity:.45; animation:float 9s ease-in-out infinite alternate; pointer-events:none; }
        .bg-blob:nth-child(1){ width:520px; height:520px; background:#0d47a1; top:-120px; left:-160px; animation-delay:0s; }
        .bg-blob:nth-child(2){ width:380px; height:380px; background:#1565c0; bottom:-80px; right:-100px; animation-delay:3s; }
        .bg-blob:nth-child(3){ width:280px; height:280px; background:#42a5f5; top:40%; left:60%; animation-delay:6s; }
        @keyframes float { 0%{transform:translate(0,0) scale(1)} 100%{transform:translate(30px,-30px) scale(1.08)} }

        .card-wrapper {
            position: relative; z-index:10;
            display: flex;
            width: min(900px, 95vw);
            min-height: 480px;
            border-radius: 24px;
            overflow: hidden;
            box-shadow: var(--shadow);
            animation: slideUp .7s cubic-bezier(.22,1,.36,1) both;
        }
        @keyframes slideUp { from{opacity:0;transform:translateY(48px) scale(.97)} to{opacity:1;transform:translateY(0) scale(1)} }

        /* ── Panel izquierdo VIDEO ── */
        .panel-left {
            flex: 1.1;
            position: relative;
            overflow: hidden;
            display: flex;
            flex-direction: column;
            align-items: center;
            justify-content: center;
            padding: 48px 36px;
        }
        .panel-video { position:absolute; top:0; left:0; width:100%; height:100%; object-fit:cover; z-index:0; }
        .panel-overlay {
            position:absolute; top:0; left:0; width:100%; height:100%; z-index:1;
            background: linear-gradient(160deg, rgba(10,61,143,.72) 0%, rgba(13,71,161,.65) 50%, rgba(8,47,110,.78) 100%);
        }
        .panel-left::before { content:''; position:absolute; width:340px; height:340px; border-radius:50%; background:rgba(255,255,255,.04); top:-80px; left:-80px; z-index:2; }
        .panel-left::after  { content:''; position:absolute; width:220px; height:220px; border-radius:50%; background:rgba(255,255,255,.05); bottom:-50px; right:-60px; z-index:2; }
        .wave-svg { position:absolute; bottom:0; left:0; right:0; height:120px; opacity:.18; z-index:3; }

        .logo-wrap { position:relative; z-index:4; text-align:center; margin-bottom:28px; }
        .logo-emblem { display:flex; align-items:center; justify-content:center; margin:0 auto 14px; }
        .logo-emblem img { width:220px; height:auto; object-fit:contain; filter:drop-shadow(0 2px 12px rgba(0,0,0,.4)); }
        .brand-sub { font-size:.78rem; color:rgba(255,255,255,.80); font-weight:300; letter-spacing:1px; margin-top:4px; text-transform:uppercase; }

        .welcome-text { position:relative; z-index:4; text-align:center; }
        .welcome-text h2 { font-family:'Nunito',sans-serif; font-weight:700; font-size:1.5rem; color:#fff; margin-bottom:8px; text-shadow:0 2px 8px rgba(0,0,0,.3); }
        .welcome-text p  { font-size:.82rem; color:rgba(255,255,255,.80); line-height:1.6; max-width:240px; text-shadow:0 1px 4px rgba(0,0,0,.3); }

        .video-indicator {
            position:absolute; bottom:16px; left:16px; z-index:5;
            display:flex; align-items:center; gap:6px;
            background:rgba(0,0,0,.3); backdrop-filter:blur(8px);
            border:1px solid rgba(255,255,255,.15); border-radius:20px;
            padding:4px 10px; cursor:pointer; transition:background .2s;
        }
        .video-indicator:hover { background:rgba(0,0,0,.45); }
        .video-indicator i    { color:rgba(255,255,255,.75); font-size:.7rem; }
        .video-indicator span { font-size:.65rem; color:rgba(255,255,255,.6); font-family:'Poppins',sans-serif; letter-spacing:.5px; }

        /* ── Panel derecho ── */
        .panel-right {
            flex:1; background:rgba(255,255,255,.97);
            display:flex; flex-direction:column; justify-content:center;
            padding:52px 44px;
        }
        .form-heading     { font-family:'Nunito',sans-serif; font-weight:800; font-size:1.75rem; color:var(--blue-dark); margin-bottom:6px; }
        .form-heading-sub { font-size:.82rem; color:#7a8fa8; margin-bottom:32px; }

        .input-group { margin-bottom:20px; }
        .input-group label {
            display:flex; align-items:center; gap:7px;
            font-size:.78rem; font-weight:600; color:var(--blue-mid);
            margin-bottom:7px; text-transform:uppercase; letter-spacing:.6px;
        }
        .input-group label i { font-size:.85rem; color:var(--blue-main); }
        .input-field {
            width:100%; padding:12px 16px;
            border:1.5px solid #dde6f0; border-radius:10px;
            font-family:'Poppins',sans-serif; font-size:.9rem; color:#1a2a40;
            background:#f4f8fd; transition:border-color .25s, box-shadow .25s, background .25s; outline:none;
        }
        .input-field:focus { border-color:var(--blue-main); background:#fff; box-shadow:0 0 0 4px rgba(30,136,229,.12); }
        .input-field::placeholder { color:#b0bec5; }

        .btn-row { display:flex; gap:12px; margin-top:10px; }
        .btn-login {
            flex:1; padding:13px; border:none; border-radius:10px;
            background:linear-gradient(135deg, var(--blue-mid), var(--blue-main));
            color:#fff; font-family:'Nunito',sans-serif; font-weight:700; font-size:1rem;
            letter-spacing:.5px; cursor:pointer;
            transition:opacity .2s, transform .15s, box-shadow .2s;
            box-shadow:0 6px 20px rgba(30,136,229,.35);
        }
        .btn-login:hover { opacity:.92; transform:translateY(-1px); box-shadow:0 10px 28px rgba(30,136,229,.42); }
        .btn-clear {
            padding:13px 22px; border:1.5px solid #dde6f0; border-radius:10px;
            background:#fff; color:#7a8fa8; font-family:'Nunito',sans-serif;
            font-weight:700; font-size:.9rem; cursor:pointer; transition:background .2s, color .2s;
        }
        .btn-clear:hover { background:#f0f4f9; color:var(--blue-mid); }

        .forgot { margin-top:22px; text-align:center; font-size:.8rem; color:#7a8fa8; }
        .forgot a { color:var(--blue-main); font-weight:600; text-decoration:none; transition:color .2s; }
        .forgot a:hover { color:var(--blue-dark); text-decoration:underline; }

        /* Mensajes */
        .alert-box {
            display:flex; align-items:flex-start; gap:12px;
            padding:14px 16px; border-radius:12px;
            font-size:.85rem; font-weight:600; margin-top:16px;
            animation: fadeIn .4s ease;
        }
        @keyframes fadeIn { from{opacity:0;transform:translateY(-6px)} to{opacity:1;transform:translateY(0)} }
        .alert-box i { font-size:1.1rem; margin-top:1px; flex-shrink:0; }
        .alert-error   { background:#fff3f3; border:1.5px solid #ffc5c5; color:#c62828; }
        .alert-error i { color:#e53935; }
        .alert-success   { background:#f0fff4; border:1.5px solid #b2dfdb; color:#2e7d32; }
        .alert-success i { color:#43a047; }
        .alert-hidden { display:none!important; }

        /* Resultado (cambio / incorrecta) */
        .result-icon-wrap {
            width:72px; height:72px; border-radius:50%;
            display:flex; align-items:center; justify-content:center;
            margin:0 auto 20px; font-size:2rem;
        }
        .result-icon-wrap.success { background:#e8f5e9; color:#43a047; }
        .result-icon-wrap.danger  { background:#fff3f3; color:#e53935; }
        .result-title { font-family:'Nunito',sans-serif; font-weight:800; font-size:1.4rem; color:var(--blue-dark); margin-bottom:8px; text-align:center; }
        .result-sub   { font-size:.85rem; color:#7a8fa8; text-align:center; margin-bottom:28px; line-height:1.6; }

        @media(max-width:640px) { .panel-left{display:none} .panel-right{padding:40px 28px} .card-wrapper{min-height:unset} }
</style>
</head>
<body>
    <div class="bg-blob"></div>
    <div class="bg-blob"></div>
    <div class="bg-blob"></div>
    <div class="card-wrapper">

        <div class="panel-left">
            <video class="panel-video" id="bgVideo" autoplay muted loop playsinline preload="auto">
                <source src="../../INTECAP.mp4" type="video/mp4">
            </video>
            <div class="panel-overlay"></div>
            <div class="logo-wrap">
                <div class="logo-emblem">
                    <img src="data:image/png;base64," alt="INTECAP">
                </div>
                <div class="brand-sub">Centro de Capacitación — Quiché</div>
            </div>
            <div class="welcome-text">
                <h2>Recuperar Contraseña</h2>
                <p>Restablece tu acceso al sistema de gestión de INTECAP Quiché.</p>
            </div>
            <svg class="wave-svg" viewBox="0 0 900 120" preserveAspectRatio="none" xmlns="http://www.w3.org/2000/svg">
                <path d="M0,60 C150,120 350,0 600,60 C750,100 850,20 900,60 L900,120 L0,120 Z" fill="white"/>
            </svg>
            <div class="video-indicator" onclick="toggleMute()" title="Activar/desactivar sonido">
                <i class="fa-solid fa-volume-xmark" id="muteIcon"></i>
                <span id="muteLabel">Sin sonido</span>
            </div>
        </div>

        <div class="panel-right">
            <div class="form-heading">Recuperar Contraseña</div>
            <div class="form-heading-sub">Ingresa tu usuario y establece una nueva contraseña</div>

            <form action="../../modelos/pass_olvidada.php" method="post" autocomplete="off">
                <div class="input-group">
                    <label for="nom_usuario"><i class="fa-solid fa-user"></i>Usuario</label>
                    <input type="text" id="nom_usuario" name="nom_usuario" class="input-field" placeholder="Nombre de usuario" required>
                </div>
                <div class="input-group">
                    <label for="contrasena"><i class="fa-solid fa-lock"></i>Nueva Contraseña</label>
                    <input type="password" id="contrasena" name="contraseña" onkeyup="comparar();" class="input-field" placeholder="••••••••" required>
                </div>
                <div class="input-group">
                    <label for="contrasena1"><i class="fa-solid fa-lock-open"></i>Confirmar Contraseña</label>
                    <input type="password" id="contrasena1" name="contraseña1" onkeyup="comparar();" class="input-field" placeholder="••••••••" required>
                </div>

                <div id="passError" class="alert-box alert-error alert-hidden">
                    <i class="fa-solid fa-triangle-exclamation"></i>
                    <span>Las contraseñas no coinciden</span>
                </div>

                <div class="btn-row" style="margin-top:20px;">
                    <button type="submit" class="btn-login" name="add" id="addBtn">
                        <i class="fa-solid fa-key" style="margin-right:7px;"></i>Cambiar Contraseña
                    </button>
                    <button type="button" class="btn-clear" onclick="window.location.href='../../index.php'">
                        <i class="fa-solid fa-xmark" style="margin-right:5px;"></i>Cancelar
                    </button>
                </div>
            </form>

            <div class="forgot">
                ¿Recordaste tu contraseña?
                <a href="../../index.php">Volver al inicio</a>
            </div>
        </div>
    </div>
</body>
</html>

    <script>
        function toggleMute(){
            const v=document.getElementById('bgVideo');
            const ic=document.getElementById('muteIcon');
            const lb=document.getElementById('muteLabel');
            v.muted=!v.muted;
            if(v.muted){ ic.className='fa-solid fa-volume-xmark'; lb.textContent='Sin sonido'; }
            else        { ic.className='fa-solid fa-volume-high';  lb.textContent='Con sonido';  }
        }
        document.addEventListener('DOMContentLoaded',()=>{
            const v=document.getElementById('bgVideo');
            if(v) v.play().catch(()=>{});
        });
    </script>
    <script>
        function comparar(){
            const p1  = document.getElementById('contrasena').value;
            const p2  = document.getElementById('contrasena1').value;
            const err = document.getElementById('passError');
            const btn = document.getElementById('addBtn');
            if(p1 !== p2){
                err.classList.remove('alert-hidden');
                btn.disabled = true;
                btn.style.opacity = '.55';
            } else {
                err.classList.add('alert-hidden');
                btn.disabled = false;
                btn.style.opacity = '1';
            }
        }
    </script>